mapper.update:
UPDATE QUESTION
SET ANALYSIS_CONTENT = #{analysisContent},
    ANALYSIS_IMAGE_BASE64 = #{analysisImageBase64},
    UPDATED_TIME = #{updatedTime}
WHERE QUESTION_ID = #{questionId}
  AND USER_ID = #{userId}
  AND QUESTION_STATUS = 1

mapper.sql:
USER_ID = #{userId}
AND QUESTION_STATUS = 1

    AND QUESTION_CONTENT LIKE CONCAT('%', #{keyword}, '%')


    AND QUESTION_CATEGORY = #{questionType}


    AND QUESTION_YEAR = #{questionYear}


    AND QUESTION_SOURCE = #{questionSource}


    AND QUESTION_JOIN_DATE = #{questionJoinDate}

mapper.select:
SELECT 
FROM QUESTION
WHERE QUESTION_ID = #{questionId}
  AND USER_ID = #{userId}
  AND QUESTION_STATUS = 1
LIMIT 1

SELECT 
FROM QUESTION
WHERE QUESTION_STATUS = 1
  AND USER_ID = #{userId}

    AND QUESTION_CATEGORY = #{questionType}


    AND QUESTION_YEAR = #{questionYear}


    AND QUESTION_SOURCE = #{questionSource}


    AND EXISTS (
        SELECT 1
        FROM ANSWER_RECORD ar
        WHERE ar.USER_ID = #{userId}
          AND ar.QUESTION_ID = QUESTION.QUESTION_ID
    )


    AND NOT EXISTS (
        SELECT 1
        FROM ANSWER_RECORD ar
        WHERE ar.USER_ID = #{userId}
          AND ar.QUESTION_ID = QUESTION.QUESTION_ID
    )

ORDER BY RAND()
LIMIT #{size}

SELECT 
FROM QUESTION
WHERE QUESTION_STATUS = 1
  AND USER_ID = #{userId}

    AND QUESTION_CATEGORY = #{questionType}


    AND QUESTION_YEAR = #{questionYear}


    AND QUESTION_SOURCE = #{questionSource}

ORDER BY QUESTION_ID ASC
LIMIT #{offset}, #{pageSize}

SELECT 
FROM QUESTION q
INNER JOIN (
    SELECT DISTINCT QUESTION_ID
    FROM ANSWER_RECORD
    WHERE USER_ID = #{userId}
      AND IS_CORRECT = 0
) r ON r.QUESTION_ID = q.QUESTION_ID
WHERE q.QUESTION_STATUS = 1
  AND q.USER_ID = #{userId}

    AND q.QUESTION_CATEGORY = #{questionType}


    AND q.QUESTION_YEAR = #{questionYear}


    AND q.QUESTION_SOURCE = #{questionSource}

ORDER BY RAND()
LIMIT #{size}
